//go:build e2e

package e2e

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"os/exec"
	"sync"
	"testing"
	"time"

	"github.com/pyrycode/pyrycode/internal/control"
)

// StdioAttachClient is a programmatic peer for `pyry attach --stdio`,
// wired via plain os.Pipe() — no PTY, no terminal, no raw mode. Tests
// drive the supervised session by writing to the client's stdin pipe
// (Write) and reading from its stdout pipe (ReadUntil). Close closes
// the stdin pipe, which propagates EOF through the attach client and
// ends the attach cleanly without destroying the session.
//
// Returned by startStdioAttach. Cleanup is registered via t.Cleanup
// at construction.
type StdioAttachClient struct {
	// SessionID is the id of the session this client is attached to,
	// as returned by control.SessionsNew. Exposed for diagnostics and
	// for tests that want to drive other CLI verbs against the same
	// session.
	SessionID string

	// SocketPath / HomeDir mirror the daemon harness fields.
	SocketPath string
	HomeDir    string

	// Stderr captures the attach client's stderr. Empty in steady
	// state — `--stdio` mode suppresses pyry's own stderr noise — so
	// any content here is a failure diagnostic.
	Stderr *bytes.Buffer

	inputW  *os.File // parent's write end of attach client's stdin
	outputR *os.File // parent's read end of attach client's stdout

	daemonCmd  *exec.Cmd
	daemonDone chan struct{}
	daemonErr  *bytes.Buffer

	attachCmd  *exec.Cmd
	attachDone chan struct{}

	cleanupOnce sync.Once
}

// startStdioAttach brings up a pyry daemon in bridge mode (helper-as-
// claude in echo mode), creates a fresh session via control.SessionsNew
// with the given label, and spawns `pyry attach --stdio <id>` whose
// stdin and stdout are wired to plain os.Pipe()s. Returns a
// StdioAttachClient the test uses to write/read bytes.
//
// label is the human-facing session label passed to sessions.new. Pass
// "" for unlabeled (the server treats nil and empty-Label identically).
//
// Skips the test (t.Skip) if os.Pipe() fails — extremely rare, only
// observed in heavily sandboxed containers without /dev/null-style fd
// allocation. Fails the test on any other startup error (daemon spawn,
// readiness timeout, sessions.new wire error, attach client spawn,
// attach client early exit).
func startStdioAttach(t *testing.T, label string) *StdioAttachClient {
	t.Helper()

	// Probe pipe availability up front. AC#3 — same gating shape as the
	// PTY harness's pty.Open skip.
	inputR, inputW, err := os.Pipe()
	if err != nil {
		t.Skipf("e2e: os.Pipe unavailable: %v", err)
	}
	outputR, outputW, err := os.Pipe()
	if err != nil {
		_ = inputR.Close()
		_ = inputW.Close()
		t.Skipf("e2e: os.Pipe unavailable: %v", err)
	}

	// Short prefix keeps the socket path under macOS's 104-byte sun_path
	// limit; t.TempDir() embeds the (long) test name and risks overflow.
	home, err := os.MkdirTemp("", "pyry-as-*")
	if err != nil {
		_ = inputR.Close()
		_ = inputW.Close()
		_ = outputR.Close()
		_ = outputW.Close()
		t.Fatalf("e2e: mkdtemp home: %v", err)
	}
	t.Cleanup(func() { _ = os.RemoveAll(home) })

	socket, daemonCmd, _, daemonErr, daemonDone := spawnAttachableDaemon(t, home)

	c := &StdioAttachClient{
		SocketPath: socket,
		HomeDir:    home,
		Stderr:     &bytes.Buffer{},
		inputW:     inputW,
		outputR:    outputR,
		daemonCmd:  daemonCmd,
		daemonDone: daemonDone,
		daemonErr:  daemonErr,
	}
	t.Cleanup(func() { c.teardown(t) })

	if err := waitDaemonReady(socket, daemonDone, daemonErr); err != nil {
		_ = inputR.Close()
		_ = outputW.Close()
		t.Fatalf("e2e: %v", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	id, err := control.SessionsNew(ctx, socket, label)
	if err != nil {
		_ = inputR.Close()
		_ = outputW.Close()
		t.Fatalf("e2e: sessions.new: %v", err)
	}
	c.SessionID = id

	bin := ensurePyryBuilt(t)
	attachCmd := exec.Command(bin, "attach", "-pyry-socket="+socket, "--stdio", id)
	attachCmd.Stdin = inputR
	attachCmd.Stdout = outputW
	attachCmd.Stderr = c.Stderr
	attachCmd.Env = childEnv(home)

	if err := attachCmd.Start(); err != nil {
		_ = inputR.Close()
		_ = outputW.Close()
		t.Fatalf("e2e: pyry attach --stdio start: %v", err)
	}

	// The child holds its own dups of inputR and outputW. Close the
	// parent's copies so EOF on outputR corresponds to child-stdout-close
	// (not a reference held by the parent), and so closing inputW from
	// the test propagates EOF to the child's stdin.
	_ = inputR.Close()
	_ = outputW.Close()

	attachDone := make(chan struct{})
	go func() {
		_ = attachCmd.Wait()
		close(attachDone)
	}()
	c.attachCmd = attachCmd
	c.attachDone = attachDone

	// If the attach client dies in handshake, surface that early instead
	// of letting the test wait out its read deadline.
	select {
	case <-attachDone:
		exit := -1
		if attachCmd.ProcessState != nil {
			exit = attachCmd.ProcessState.ExitCode()
		}
		t.Fatalf("e2e: pyry attach --stdio exited before round-trip (exit=%d)\nattach stderr:\n%s\ndaemon stderr:\n%s",
			exit, c.Stderr.String(), daemonErr.String())
	case <-time.After(500 * time.Millisecond):
	}

	return c
}

// Write writes b to the attach client's stdin pipe. Returns the
// underlying os.File.Write result; callers typically expect len(b),
// nil on a healthy attach.
func (c *StdioAttachClient) Write(b []byte) (int, error) {
	return c.inputW.Write(b)
}

// ReadUntil reads from the attach client's stdout pipe in a loop in a
// background goroutine, accumulating bytes, until needle appears in the
// accumulated buffer or the overall deadline elapses. The accumulated
// bytes (including any pre-needle banner emitted by the helper) are
// returned regardless of outcome.
//
// Mirrors readUntilContains in attach_pty_test.go: os.Pipe ends share
// the no-SetReadDeadline trait with PTY masters on darwin, so the
// timeout is enforced by the caller rather than per-read.
func (c *StdioAttachClient) ReadUntil(needle []byte, total time.Duration) ([]byte, error) {
	type readResult struct {
		buf []byte
		err error
	}
	ch := make(chan readResult, 1)
	var seen bytes.Buffer

	read := func() {
		buf := make([]byte, 4096)
		n, err := c.outputR.Read(buf)
		ch <- readResult{buf: buf[:n], err: err}
	}

	deadline := time.Now().Add(total)
	go read()
	for {
		select {
		case res := <-ch:
			if len(res.buf) > 0 {
				seen.Write(res.buf)
				if bytes.Contains(seen.Bytes(), needle) {
					return seen.Bytes(), nil
				}
			}
			if res.err != nil {
				return seen.Bytes(), fmt.Errorf("read: %w (seen %q)", res.err, seen.Bytes())
			}
			go read()
		case <-time.After(time.Until(deadline)):
			return seen.Bytes(), fmt.Errorf("timeout after %s; seen %d bytes: %q", total, seen.Len(), seen.Bytes())
		}
	}
}

// Close closes the attach client's stdin pipe (delivering EOF to the
// child's AttachStdio input loop), waits up to ~2s for the child to
// exit cleanly, and returns its exit code. Subsequent calls return
// the same exit code from the cached ProcessState.
//
// Idempotent. Also called from t.Cleanup; whichever fires first wins.
func (c *StdioAttachClient) Close(t *testing.T) int {
	t.Helper()
	c.teardown(t)
	if c.attachCmd != nil && c.attachCmd.ProcessState != nil {
		return c.attachCmd.ProcessState.ExitCode()
	}
	return -1
}

// teardown is the sync.Once-wrapped cleanup body. Ordering:
//  1. inputW.Close()       — sends EOF to child stdin → clean detach
//  2. wait attachDone (≤ ~2s) → killSpawned(attachCmd) on timeout
//  3. outputR.Close()      — unblocks any in-flight ReadUntil
//  4. killSpawned(daemonCmd)
//  5. os.Remove(socketPath)
func (c *StdioAttachClient) teardown(t *testing.T) {
	t.Helper()
	c.cleanupOnce.Do(func() {
		if c.inputW != nil {
			_ = c.inputW.Close()
		}
		if c.attachCmd != nil && c.attachCmd.Process != nil {
			select {
			case <-c.attachDone:
			case <-time.After(2 * time.Second):
				killSpawned(t, c.attachCmd, c.attachDone)
			}
		}
		if c.outputR != nil {
			_ = c.outputR.Close()
		}
		if c.daemonCmd != nil && c.daemonCmd.Process != nil {
			killSpawned(t, c.daemonCmd, c.daemonDone)
		}
		_ = os.Remove(c.SocketPath)
	})
}

//go:build e2e

package e2e

import (
	"bytes"
	"testing"
	"time"
)

// TestE2E_AttachStdio_BytesRoundTrip proves that a byte written into a
// programmatic parent's stdin-of-`pyry attach --stdio` travels: parent
// pipe → attach client → control socket → bridge → supervisor PTY →
// supervised helper → and back through the attach client's stdout into
// the parent's read pipe. The helper is the e2e test binary running
// TestHelperProcess in echo mode (line-buffered). The test writes one
// nonce-tagged line and asserts the same line appears on output within
// a generous deadline; pre-line banner bytes (the helper's startup
// "PYRY_E2E_STARTED pid=…\n") are accumulated and ignored, identical
// to the PTY harness's readUntilContains discipline.
//
// This test is the smallest meaningful exercise of the stdio-attach
// shape end-to-end. Follow-up tickets (1.3a-e2e-no-pty: assert no PTY
// fd open in the client; 1.3c-2-e2e-*: foreground auto-attach) reuse
// startStdioAttach for their own scenarios.
func TestE2E_AttachStdio_BytesRoundTrip(t *testing.T) {
	// Blocked on #167 — `pyry attach --stdio` is rejected by
	// parseClientFlags before parseAttachArgs runs, so the harness can't
	// drive the CLI through. Once #167 lands, remove this skip and the
	// existing harness body should make the test pass unchanged.
	t.Skip("blocked on #167 — pyry attach --stdio rejected by parseClientFlags")

	c := startStdioAttach(t, "stdio-roundtrip")

	// Trailing \n is required: the helper's echo mode is line-buffered
	// and only flushes a line when it sees \n.
	payload := []byte("pyry-stdio-roundtrip-" + tinyNonce() + "\n")

	if _, err := c.Write(payload); err != nil {
		t.Fatalf("write: %v", err)
	}

	seen, err := c.ReadUntil(payload, 5*time.Second)
	if err != nil {
		t.Fatalf("did not observe payload back: %v\nstderr:\n%s",
			err, c.Stderr.String())
	}

	// Defensive: the needle must appear *after* any banner. The
	// ReadUntil contract already guarantees needle ∈ seen on nil err,
	// so this is a smoke check that the buffer wasn't returned empty
	// by an unlikely API regression.
	if !bytes.Contains(seen, payload) {
		t.Fatalf("ReadUntil returned without payload in buffer: %q", seen)
	}
}

//go:build e2e || e2e_install

package e2e

import (
	"bytes"
	"fmt"
	"net"
	"os"
	"os/exec"
	"path/filepath"
	"sync"
	"syscall"
	"testing"
	"time"

	"github.com/creack/pty"
	"golang.org/x/term"
)

// AttachHarness owns one running pyry daemon configured for interactive
// attach (bridge mode, the e2e test binary as claude in echo mode), the
// master side of a creack/pty pair, and the running `pyry attach`
// subprocess whose stdio is bound to the slave.
//
// Returned by StartAttach; cleanup is registered via t.Cleanup. Tests
// interact with Master to write input bytes and read output bytes back.
type AttachHarness struct {
	// Master is the PTY master. Tests write input bytes here and read
	// output bytes back. Closed by cleanup.
	Master *os.File

	// SocketPath is the daemon's control socket. Exposed so follow-up
	// tickets can drive additional verbs against the same daemon
	// (e.g. a second `pyry attach` to assert ErrBridgeBusy).
	SocketPath string

	// HomeDir is the daemon's $HOME (a fresh t.TempDir).
	HomeDir string

	daemonCmd  *exec.Cmd
	daemonDone chan struct{}
	daemonOut  *bytes.Buffer
	daemonErr  *bytes.Buffer

	attachCmd  *exec.Cmd
	attachDone chan struct{}

	slave    *os.File
	origTerm *term.State

	cleanupOnce sync.Once
}

// StartAttach spawns a pyry daemon in bridge mode whose supervised claude
// is the e2e test binary running TestHelperProcess in echo mode, opens a
// creack/pty pair, and spawns `pyry attach` with the slave on stdio. The
// returned harness exposes Master for the test to write/read.
//
// sessionID selects the session to attach to. Empty means "the bootstrap
// session", which is the only session this harness creates.
//
// Skips the test (t.Skip) if pty.Open fails — some hosts (sandboxed CI,
// minimal containers) lack a usable /dev/ptmx. Fails the test on any
// other startup error.
func StartAttach(t *testing.T, sessionID string) *AttachHarness {
	t.Helper()

	// Probe PTY availability up front. A clean t.Skip is faster than
	// spawning pyry, racing readiness, then tearing down. AC#5.
	master, slave, err := pty.Open()
	if err != nil {
		t.Skipf("e2e: pty.Open unavailable: %v", err)
	}

	// Snapshot the parent test process's stdin terminal state defensively.
	// No code path in this harness should modify it, but AC#4 calls for a
	// restore-on-cleanup guarantee.
	var origTerm *term.State
	if term.IsTerminal(int(os.Stdin.Fd())) {
		st, err := term.GetState(int(os.Stdin.Fd()))
		if err == nil {
			origTerm = st
		}
	}

	// os.MkdirTemp with a short prefix keeps the socket path under macOS's
	// 104-byte sun_path limit; t.TempDir() embeds the (long) test name and
	// overflows for callers like TestE2E_Attach_SurvivesClaudeRestart.
	home, err := os.MkdirTemp("", "pyry-at-*")
	if err != nil {
		t.Fatalf("e2e: mkdtemp home: %v", err)
	}
	t.Cleanup(func() { _ = os.RemoveAll(home) })
	socket, daemonCmd, daemonOut, daemonErr, daemonDone := spawnAttachableDaemon(t, home)

	a := &AttachHarness{
		Master:     master,
		SocketPath: socket,
		HomeDir:    home,
		daemonCmd:  daemonCmd,
		daemonDone: daemonDone,
		daemonOut:  daemonOut,
		daemonErr:  daemonErr,
		slave:      slave,
		origTerm:   origTerm,
	}
	t.Cleanup(func() { a.teardown(t) })

	if err := waitDaemonReady(socket, daemonDone, daemonErr); err != nil {
		t.Fatalf("e2e: %v", err)
	}

	bin := ensurePyryBuilt(t)
	attachCmd := exec.Command(bin, "attach", "-pyry-socket="+socket)
	attachCmd.Stdin = slave
	attachCmd.Stdout = slave
	attachCmd.Stderr = slave
	// Make the slave the controlling terminal of the attach client so
	// IsTerminal(stdin) returns true and term.MakeRaw kills ECHO/ICANON.
	attachCmd.SysProcAttr = &syscall.SysProcAttr{Setsid: true, Setctty: true}
	attachCmd.Env = childEnv(home)

	if err := attachCmd.Start(); err != nil {
		t.Fatalf("e2e: pyry attach start: %v", err)
	}
	attachDone := make(chan struct{})
	go func() {
		_ = attachCmd.Wait()
		close(attachDone)
	}()
	a.attachCmd = attachCmd
	a.attachDone = attachDone

	// If the attach client dies in handshake, surface that early instead
	// of letting the test wait out its read deadline.
	select {
	case <-attachDone:
		exit := -1
		if attachCmd.ProcessState != nil {
			exit = attachCmd.ProcessState.ExitCode()
		}
		t.Fatalf("e2e: pyry attach exited before round-trip (exit=%d)\ndaemon stderr:\n%s",
			exit, daemonErr.String())
	case <-time.After(500 * time.Millisecond):
	}

	return a
}

// spawnAttachableDaemon mirrors harness.spawn but with a custom claude
// (the e2e test binary running TestHelperProcess), helper-env injection
// (GO_TEST_HELPER_PROCESS=1, GO_TEST_HELPER_MODE=echo), and no sleep
// sentinel. The daemon's stdin is left at its default (/dev/null) so
// IsTerminal returns false and pyry runs in bridge mode.
func spawnAttachableDaemon(t *testing.T, home string) (string, *exec.Cmd, *bytes.Buffer, *bytes.Buffer, chan struct{}) {
	t.Helper()
	bin := ensurePyryBuilt(t)
	socket := filepath.Join(home, "pyry.sock")

	stdout := &bytes.Buffer{}
	stderr := &bytes.Buffer{}

	args := []string{
		"-pyry-socket=" + socket,
		"-pyry-name=test",
		"-pyry-claude=" + os.Args[0],
		"-pyry-idle-timeout=0",
		// Default ResumeLast prepends --continue on respawn; the test
		// helper is a Go test binary that doesn't recognize that flag.
		"-pyry-resume=false",
		"--",
		"-test.run=TestHelperProcess",
	}
	cmd := exec.Command(bin, args...)
	cmd.Stdout = stdout
	cmd.Stderr = stderr
	// supervisor.runOnce does cmd.Env = append(os.Environ(), helperEnv...),
	// so env set on the daemon flows through to the supervised helper.
	cmd.Env = append(childEnv(home),
		"GO_TEST_HELPER_PROCESS=1",
		"GO_TEST_HELPER_MODE=echo",
	)

	if err := cmd.Start(); err != nil {
		t.Fatalf("e2e: pyry attachable daemon start: %v", err)
	}

	doneCh := make(chan struct{})
	go func() {
		_ = cmd.Wait()
		close(doneCh)
	}()

	return socket, cmd, stdout, stderr, doneCh
}

// waitDaemonReady polls the socket like Harness.waitForReady. Short-
// circuits if the daemon exits before ready (e.g. flag parse error).
func waitDaemonReady(socket string, doneCh chan struct{}, errBuf *bytes.Buffer) error {
	deadline := time.Now().Add(readyDeadline)
	for time.Now().Before(deadline) {
		if _, err := os.Stat(socket); err == nil {
			c, err := net.Dial("unix", socket)
			if err == nil {
				_ = c.Close()
				return nil
			}
		}
		select {
		case <-doneCh:
			return fmt.Errorf("pyry exited before ready: %s", errBuf.String())
		case <-time.After(readyPollGap):
		}
	}
	return fmt.Errorf("pyry not ready within %s", readyDeadline)
}

// WaitDetach blocks until the attach client process exits or timeout
// elapses, then returns its exit code. Fails the test on timeout — a
// clean detach should be near-instant; a generous deadline here is a
// safety net, not a steady-state expectation.
//
// Safe to call after writing the detach sequence to Master. Subsequent
// calls return the same exit code (the attachDone channel stays closed
// once Wait() returns; ProcessState is set).
func (a *AttachHarness) WaitDetach(t *testing.T, timeout time.Duration) int {
	t.Helper()
	select {
	case <-a.attachDone:
		if a.attachCmd.ProcessState == nil {
			t.Fatalf("attach process state nil after Wait")
		}
		return a.attachCmd.ProcessState.ExitCode()
	case <-time.After(timeout):
		t.Fatalf("attach client did not exit within %s after detach", timeout)
		return -1 // unreachable
	}
}

// Run invokes the cached pyry binary against this harness's daemon
// socket with HOME=a.HomeDir and the verb's args appended. Mirrors
// Harness.Run — same auto-injection of -pyry-socket=, same RunResult
// shape, same timeout. Used by tests that need to drive a CLI verb
// against the same daemon the attach client is bound to.
func (a *AttachHarness) Run(t *testing.T, verb string, args ...string) RunResult {
	t.Helper()
	return runVerb(t, a.SocketPath, a.HomeDir, verb, args...)
}

// teardown closes master and slave (delivering SIGHUP/EOF to the attach
// client), then SIGTERM-grace-SIGKILLs both the attach client and the
// daemon, then removes the socket and restores the parent's terminal
// state. Idempotent via sync.Once.
func (a *AttachHarness) teardown(t *testing.T) {
	a.cleanupOnce.Do(func() {
		if a.Master != nil {
			_ = a.Master.Close()
		}
		if a.slave != nil {
			_ = a.slave.Close()
		}
		if a.attachCmd != nil && a.attachCmd.Process != nil {
			killSpawned(t, a.attachCmd, a.attachDone)
		}
		if a.daemonCmd != nil && a.daemonCmd.Process != nil {
			killSpawned(t, a.daemonCmd, a.daemonDone)
		}
		_ = os.Remove(a.SocketPath)
		if a.origTerm != nil {
			_ = term.Restore(int(os.Stdin.Fd()), a.origTerm)
		}
	})
}

